var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"크으윽!!","JPN":"くううっ！！","ENG":"Ugh!","TWN":"嗚！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대장! 괜찮아?!","JPN":"隊長！　大丈夫か！？","ENG":"Cap! Are you okay?","TWN":"隊長！沒事吧？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"제길, 최고출력으로 쐈는데 전혀 통하질 않아!","JPN":"くそ、最高出力で撃ったのに、まったく効かない！","ENG":"That was a max power shot, and it's just not working at all!","TWN":"可惡，已經用最大輸出射擊了，竟然完全沒有用！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저 녀석은...... 약점도 없는 건가?","JPN":"あいつ……弱点がないの？","ENG":"Does she have any weaknesses at all?","TWN":"那個傢伙……難道沒有弱點嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"어떻게 된 거지, 서윤?","JPN":"どうした、アオイ・シズカ？","ENG":"What happened, Seo Yoon?","TWN":"怎麼了，徐芸？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이 정도로 내게 복수하기엔 역부족일 텐데?","JPN":"こんなものでは、私に復讐できないぞ？","ENG":"This isn't much of a revenge, is it?","TWN":"這種程度的話還不足以向我報仇吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"아니면 지금이라도 도망치지 않은 걸 후회하고 있나?","JPN":"それとも今になって、逃げなかったのを悔いているのか？","ENG":"Or are you feeling sorry that you didn't run away in the first place?","TWN":"還是說妳正在後悔沒有及時逃跑？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"너, 이 자식...... 이제와서 누가 후회 따윌 할 것 같아?","JPN":"この……ここまできて、そんなわけないでしょ！","ENG":"Shut up! I don't feel sorry for anything!","TWN":"妳這傢伙……都到這個地步了誰會後悔啊？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_FUSION","text":{"KOREA":"괴, 괴로워...... 이젠 싸우고 싶지 않아...... 더 이상 부활하고 싶지 않아......","JPN":"く、苦しい……もう戦いたくない……これ以上、復活したくない……","ENG":"Th-this is too painful... I don't want to fight anymore... I don't want to come back to life...","TWN":"好，好痛苦……不想再戰鬥了……不想再復活了……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_FUSION","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_FUSION","text":{"KOREA":"제발...... 죽여줘...... 크아악!!","JPN":"頼む……殺してくれ……ぐああ！！","ENG":"Please... Kill me... Aaaargh!","TWN":"拜託……殺了我吧……啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_FUSION","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님! 이대로 리플레이서 나이트와 폰을 처치해 봐야 퀸에게 진화용 리플레이서 인자를 보급해 주는 일밖에 되지 않습니다!","JPN":"大佐！　このままリプレイサー・ナイトとポーンを処理しても、\\nクイーンに進化用のリプレイサーファクターが補給されるだけです！","ENG":"Colonel! We're only supplying Queen with Replacer Factors for evolution by taking down Replacer Knight and Pawn!","TWN":"上校！這樣打倒克隆·騎士和兵卒，只會幫女皇補給進化用的克隆因子而已！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나도 알아! 하지만 방법이 없잖아?!","JPN":"わかってる！　けど、他にどうしようもないだろ！？","ENG":"I know! But what choice do we have?","TWN":"我也知道啊！但哪有什麼辦法啊？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"후퇴할 게 아니라면 지금은 어떻게든 시간을 끄는 수밖에 없어!","JPN":"退却しない以上、今はどうにかして時間稼ぎをするしかない！","ENG":"If we're not falling back, we have to keep buying time,","TWN":"不能撤退的話，現在就只能想辦法拖延時間！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 사이에 중장님과 실비아가 대응책을 찾을 수 있도록!","JPN":"その間に中将やシルビアが対策を立てられるようにな！","ENG":"until Lieutenant General and Sylvia come up with a countermeasure!","TWN":"讓中將大人和希爾維亞能在這個空檔找出解決方法！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......어쩔 수 없군.","JPN":"……仕方あるまい。","ENG":"I guess I have no choice.","TWN":"……沒辦法了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};